import UIKit

class UniversalLinkHandler {
    
    static let shared = UniversalLinkHandler()
    
    private let allowedHosts: Set<String> = ["myapp.com", "www.myapp.com"]
    
    private enum AllowedRoute {
        case profile(id: String)
        case paymentConfirm
        case adminSettings
        
        static func parse(from components: URLComponents) -> AllowedRoute? {
            guard let path = components.path.isEmpty ? nil : components.path else {
                return nil
            }
            
            let pathComponents = path.split(separator: "/").map(String.init)
            
            guard !pathComponents.isEmpty else { return nil }
            
            switch pathComponents[0] {
            case "profile":
                guard pathComponents.count == 2 else { return nil }
                let profileId = pathComponents[1]
                guard isValidProfileId(profileId) else { return nil }
                return .profile(id: profileId)
                
            case "payment":
                guard pathComponents.count == 2, pathComponents[1] == "confirm" else { return nil }
                return .paymentConfirm
                
            case "admin":
                guard pathComponents.count == 2, pathComponents[1] == "settings" else { return nil }
                return .adminSettings
                
            default:
                return nil
            }
        }
        
        private static func isValidProfileId(_ id: String) -> Bool {
            let allowedCharacters = CharacterSet.decimalDigits
            return !id.isEmpty && 
                   id.count <= 20 && 
                   id.rangeOfCharacter(from: allowedCharacters.inverted) == nil
        }
    }
    
    private init() {}
    
    func handleUniversalLink(_ url: URL, completion: @escaping (Bool) -> Void) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let scheme = components.scheme,
              let host = components.host else {
            completion(false)
            return
        }
        
        guard scheme == "https" else {
            completion(false)
            return
        }
        
        guard allowedHosts.contains(host) else {
            completion(false)
            return
        }
        
        guard let route = AllowedRoute.parse(from: components) else {
            completion(false)
            return
        }
        
        navigate(to: route, completion: completion)
    }
    
    private func navigate(to route: AllowedRoute, completion: @escaping (Bool) -> Void) {
        DispatchQueue.main.async {
            guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
                  let window = windowScene.windows.first,
                  let rootViewController = window.rootViewController else {
                completion(false)
                return
            }
            
            switch route {
            case .profile(let id):
                self.navigateToProfile(id: id, from: rootViewController, completion: completion)
                
            case .paymentConfirm:
                self.navigateToPaymentConfirm(from: rootViewController, completion: completion)
                
            case .adminSettings:
                self.navigateToAdminSettings(from: rootViewController, completion: completion)
            }
        }
    }
    
    private func navigateToProfile(id: String, from rootViewController: UIViewController, completion: @escaping (Bool) -> Void) {
        let profileVC = ProfileViewController()
        profileVC.profileId = id
        
        if let navController = rootViewController as? UINavigationController {
            navController.pushViewController(profileVC, animated: true)
            completion(true)
        } else if let navController = rootViewController.presentedViewController as? UINavigationController {
            navController.pushViewController(profileVC, animated: true)
            completion(true)
        } else {
            let navController = UINavigationController(rootViewController: profileVC)
            rootViewController.present(navController, animated: true) {
                completion(true)
            }
        }
    }
    
    private func navigateToPaymentConfirm(from rootViewController: UIViewController, completion: @escaping (Bool) -> Void) {
        AuthorizationService.shared.checkPaymentAccess { hasAccess in
            guard hasAccess else {
                DispatchQueue.main.async {
                    self.showUnauthorizedAlert(from: rootViewController)
                    completion(false)
                }
                return
            }
            
            DispatchQueue.main.async {
                let paymentVC = PaymentConfirmViewController()
                
                if let navController = rootViewController as? UINavigationController {
                    navController.pushViewController(paymentVC, animated: true)
                    completion(true)
                } else if let navController = rootViewController.presentedViewController as? UINavigationController {
                    navController.pushViewController(paymentVC, animated: true)
                    completion(true)
                } else {
                    let navController = UINavigationController(rootViewController: paymentVC)
                    rootViewController.present(navController, animated: true) {
                        completion(true)
                    }
                }
            }
        }
    }
    
    private func navigateToAdminSettings(from rootViewController: UIViewController, completion: @escaping (Bool) -> Void) {
        AuthorizationService.shared.checkAdminAccess { hasAccess in
            guard hasAccess else {
                DispatchQueue.main.async {
                    self.showUnauthorizedAlert(from: rootViewController)
                    completion(false)
                }
                return
            }
            
            DispatchQueue.main.async {
                let adminVC = AdminSettingsViewController()
                
                if let navController = rootViewController as? UINavigationController {
                    navController.pushViewController(adminVC, animated: true)
                    completion(true)
                } else if let navController = rootViewController.presentedViewController as? UINavigationController {
                    navController.pushViewController(adminVC, animated: true)
                    completion(true)
                } else {
                    let navController = UINavigationController(rootViewController: adminVC)
                    rootViewController.present(navController, animated: true) {
                        completion(true)
                    }
                }
            }
        }
    }
    
    private func showUnauthorizedAlert(from viewController: UIViewController) {
        let alert = UIAlertController(
            title: "Access Denied",
            message: "You don't have permission to access this feature.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        viewController.present(alert, animated: true)
    }
}

class AuthorizationService {
    static let shared = AuthorizationService()
    
    private init() {}
    
    func checkPaymentAccess(completion: @escaping (Bool) -> Void) {
        guard let userId = getCurrentUserId() else {
            completion(false)
            return
        }
        
        validateUserSession(userId: userId) { isValid in
            guard isValid else {
                completion(false)
                return
            }
            
            self.checkServerSidePaymentPermission(userId: userId, completion: completion)
        }
    }
    
    func checkAdminAccess(completion: @escaping (Bool) -> Void) {
        guard let userId = getCurrentUserId() else {
            completion(false)
            return
        }
        
        validateUserSession(userId: userId) { isValid in
            guard isValid else {
                completion(false)
                return
            }
            
            self.checkServerSideAdminPermission(userId: userId, completion: completion)
        }
    }
    
    private func getCurrentUserId() -> String? {
        return UserDefaults.standard.string(forKey: "currentUserId")
    }
    
    private func validateUserSession(userId: String, completion: @escaping (Bool) -> Void) {
        guard let sessionToken = UserDefaults.standard.string(forKey: "sessionToken") else {
            completion(false)
            return
        }
        
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.1) {
            completion(!sessionToken.isEmpty)
        }
    }
    
    private func checkServerSidePaymentPermission(userId: String, completion: @escaping (Bool) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.2) {
            completion(true)
        }
    }
    
    private func checkServerSideAdminPermission(userId: String, completion: @escaping (Bool) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.2) {
            let isAdmin = UserDefaults.standard.bool(forKey: "isAdmin")
            completion(isAdmin)
        }
    }
}

